sp_widget.client_script:
function clientController($scope, $rootScope, $http, $location, spUtil, $interpolate, $log, spAriaUtil) {
    //------------------------------------------------------------------------------------------------------------------------
    // COMPANY: DISCOVER TECHNOLOGIES
    // CUSTOMIZED BY: KARINA TORRES
    // RECURSIVE LIST TREE
    //------------------------------------------------------------------------------------------------------------------------
    // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
    //												some special characters in "instruction" or "Signature Instructions" field
    //                                          Rewrite getTaskTreeListTitleNode() to pass just an object and refactor code
    //------------------------------------------------------------------------------------------------------------------------

    var c = this;

    //spUtil.recordWatch($scope, $scope.data.table, "sys_id=" + $scope.data.sys_id);
    // NOTE: record watcher accounts for the form save change, no need to reload on form change
    // var onSaveUpdate = $scope.$on('sp.form.record.updated', refreshWidget);
    spUtil.recordWatch($scope, $scope.data.table, "u_task_tree=" + $scope.data.task_tree, function(name) {
				// DFCT0010588	
				var taskIndex;
				var changes = name.data.changes;
        var sys_id = name.data.sys_id.toString();
        switch (name.data.operation) {
            case "update":
                var arrItemChanged = c.data.tasks.filter(function(item) {
                    return item.key === sys_id;
                });
                if (arrItemChanged[0]) {
                    var itemChanged = arrItemChanged[0];
                    var itemDataChanged = false;
                    for (var change in changes) {
                        if (c.data.fieldsInModel[changes[change]]) {
                            itemDataChanged = true;
                        }
                    }
                    if (itemDataChanged) {
                        updateTaskData(itemChanged, name.data.record);
                    }
                }
                break;
            case "insert":
                if (name.data.record.parent) {
									// DFCT0010588
									taskIndex = c.data.tasks.findIndex(function(task) {
										return task.sys_id == sys_id;
									});
									if (taskIndex == -1) {
                    c.data.tasks.push(createTaskData(sys_id, name.data.record));
									}
                }
                break;
						case "delete":
							// DFCT0010588									
							taskIndex = c.data.tasks.findIndex(function(task) {
								return task.sys_id == sys_id;
							});
							if (taskIndex > -1) {
								c.data.tasks.splice(taskIndex, 1);
							}
			}
    });
    // load all of the field names used in the task tree nodes (see TaskHelpers.getTaskTreeLevelO and TaskHelpers.getTaskTitleNode)
    function createTaskData(sys_id, record) {
        var newTaskData = {};
        newTaskData.key = sys_id;
        newTaskData.sys_id = sys_id;
        for (var key in record) {
            var displayValue = '';
            var fieldLabel = '';
            var field = c.data.fieldsInModel[key];
            if (field) {
                fieldLabel = field.fieldLabel;
                if (field.keyUsesDisplayOnly) {
                    newTaskData[key] = record[key].display_value;
                }
                if (field.hasValue) {
                    newTaskData[key] = record[key].value;
                }
                if (field.hasDiplayValue) {
                    newTaskData[key + '_DisplayValue'] = record[key].display_value;
                }
                if (field.hasDisplayAndLabel) {
                    displayValue = fieldLabel + ': ' + record[key].display_value;
                    newTaskData[key + '_DisplayText'] = displayValue;
                }
                if (field.type == 'date') {
                    var date_number = getDateFromFormat(record[key].value, g_user_date_time_format);
                    newTaskData[key] = date_number;
                }
            } //if field wasn't found do nothing
        }

        // These are the custom fields in this data set, compare with other data sets and determine best way to bring together.
        var iLevel = 0;
        if (newTaskData.parent != null) {
            var arrParentItem = c.data.tasks.filter(function(item) {
                return item.key === newTaskData.parent;
            });
            iLevel = parseInt(arrParentItem[0].level);
        }
        newTaskData.level = iLevel;

        // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering; refactor function 
        // newTaskData.text = getTaskTreeListTitleNode(newTaskData, newTaskData.parent, newTaskData.task_name, newTaskData.primary_assignee, newTaskData.assigned_to, newTaskData.state, newTaskData.order);
        newTaskData.text = getTaskTreeListTitleNode(newTaskData);

        // we will expand all on initial page load
        newTaskData.expanded = true;
        // NOTE you are here, there is an issue with leaf nodes having the down chevron when they should not	
        // this should be removed
		// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering; use dot notation for state and order
        return newTaskData;
    }
    // load all of the field names used in the task tree nodes
    function updateTaskData(taskData, record) {
        for (var key in record) {
            var displayValue = '';
            var fieldLabel = '';
            var field = c.data.fieldsInModel[key];
            if (field) {
                fieldLabel = field.fieldLabel;
                if (field.keyUsesDisplayOnly) {
                    taskData[key] = record[key].display_value;
                }
                if (field.hasValue) {
                    taskData[key] = record[key].value; // this is the default value to key match
                }
                if (field.hasDiplayValue) {
                    taskData[key + '_DisplayValue'] = record[key].display_value;
                }
                if (field.hasDisplayAndLabel) {
                    displayValue = fieldLabel + ': ' + record[key].display_value;
                    taskData[key + '_DisplayText'] = displayValue;
                }
                if (field.type == 'date') {
                    var date_number = getDateFromFormat(record[key].value, g_user_date_time_format);
                    taskData[key] = date_number;
                }
            } //if field wasn't found do nothing
        }

        // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering; refactor function
        // taskData.text = getTaskTreeListTitleNode(taskData, taskData.parent, taskData.task_name, taskData.primary_assignee, taskData.assigned_to, taskData.state, taskData.order);
        taskData.text = getTaskTreeListTitleNode(taskData);

        // we will expand all on initial page load
        taskData.expanded = true;

		// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering; use dot notation for state and order 

        return taskData;
    }

    // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering; refactor function
    function getTaskTreeListTitleNode(newTaskData) {
        var assignedTo = '';
        var taskNameNumber = newTaskData.task_name;
        var taskText = {};

        if (newTaskData.parent != null) {
            taskNameNumber = newTaskData.order + ". " + newTaskData.task_name;
        }

        // STRY0099313 - When adding tasks that are unassigned, the user shows "undefined" instead of nothing.  This story fixes that as well.
        if (!!newTaskData.assigned_to && newTaskData.assigned_to != '') {
            assignedTo = '(' + newTaskData.assigned_to + ')';
        }

        taskText = {
            TaskNameNumber: taskNameNumber,
            primary_assignee: newTaskData.primary_assignee,
            assigned_to: assignedTo,
            state: newTaskData.state,
            Order: newTaskData.order
        };

        return taskText;
    }

    // STRY0093948 - the tasker form with tab is rasing this as a rootscope broadcast, updated to catch
    $rootScope.$on('$taskerTabbedForm.drillDownList.click', function(e, parms) {
        setAndExpandSelected(parms.sys_id);
    });
    $rootScope.$on('$sp.list.click', function(e, parms) {
        setAndExpandSelected(parms.sys_id);
    });
    // NOTE you are here, you need to expand/collaps	
    function extendAllAncestors(parent) {
        var itemParent = c.data.tasks.filter(function(item) {
            return item.key === parent;
        });
        if (itemParent.parent) {
            extendAllAncestors(itemParent.parent);
            itemParent.expanded = true;
            c.expand(itemParent.key);
        }
    }

    function setAndExpandSelected(sys_id) {
        c.data.sys_id = sys_id;
        // TODO - ON CHANGE EXPAND ALL NODES UP THE TREE FROM SELECTED NODE
        extendAllAncestors(sys_id);
    }

    //function refreshWidget() {
    //	$scope.server.update();
    //}

    c.openLink = function(sys_id) {
        if (c.data.sys_id == sys_id) // get called twice by gojs
            return;
        c.data.sys_id = sys_id;
        var evt = {};
        evt.sys_id = sys_id;
        evt.table = c.data.table;
        $location.search('table', evt.table).search('sys_id', evt.sys_id).search('spa', '1');
        $rootScope.$broadcast('$TaskerTaskList.click', evt);
    };

    c.findChildren = function(id) {
        var taskChildren = [];
        for (var i = 0; i < c.data.tasks.length; i++) {
            if (c.data.tasks[i].parent == id) {
                taskChildren.push(c.data.tasks[i]);
            }
        }
        return taskChildren;
    };
    c.findCurrentTask = function(id) {
        var currentTask = {};
        for (var i = 0; i < c.data.tasks.length; i++) {
            if (c.data.tasks[i].sys_id == id) {
                currentTask = c.data.tasks[i];
            }
        }
        return currentTask;
    };
    c.collapse = function(id, event) {
        var currentTask = c.findCurrentTask(id);
        var taskChildren = c.findChildren(id);

        if ($("#span" + currentTask.sys_id).hasClass("glyphicon-chevron-down")) {
            c.collapse_1(id);

        } else if ($("#span" + currentTask.sys_id).hasClass("glyphicon-chevron-right")) {
            c.expand(id);
        }
        event.stopPropagation();
    };
    c.changeState = function(id) {
        for (var r = 0; r < c.data.tasks; r++) {
            if (c.data.tasks[r].sys_id == id) {
                c.data.tasks[r].state.expanded = !c.data.tasks[r].state.expanded;
            }
        }
    };
    c.collapse_1 = function(id) {
        var currentTask = c.findCurrentTask(id);
        var taskChildren = c.findChildren(id);
        for (var x = 0; x < taskChildren.length; x++) {
            $("#span" + currentTask.sys_id).removeClass("glyphicon-chevron-down");
            $("#span" + currentTask.sys_id).addClass("glyphicon-chevron-right");
            //	$( "#" + taskChildren[x].sys_id ).css("background-color",color)
            $("#" + taskChildren[x].sys_id).css("display", "none");
            c.collapse_1(taskChildren[x].sys_id);
        }
    };

    c.expand = function(id) {
        var currentTask = c.findCurrentTask(id);
        var taskChildren = c.findChildren(id);

        for (var x = 0; x < taskChildren.length; x++) {
            $("#span" + currentTask.sys_id).removeClass("glyphicon-chevron-right");
            $("#span" + currentTask.sys_id).addClass("glyphicon-chevron-down");
            var color = 'red';
            //$( "#" + taskChildren[x].sys_id ).css("background-color",color)
            $("#" + taskChildren[x].sys_id).css("display", "block");

            c.expand(taskChildren[x].sys_id);

        }
    };

}

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: AYMAN ALZYOUD && KARINA TORRES 
// RECURSIVE LIST TREE
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 08.31.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------

div.panel-heading {
  font-size: 16px;
  font-family: "SourceSansPro", Helvetica, Arial, sans-serif;
}

span.indent {
  margin-left: 0px!important;
}

.node-task-tree {
  border-top-right-radius: 0px !important;
  border-top-left-radius: 0px !important;
  border-bottom-right-radius: 0px !important;
  border-bottom-left-radius: 0px !important;
}

.list-group-item {
	padding-right: 10px!important;
  padding-bottom: 20px!important;
  border:0px;
}

ul.list-group {
  background-color: $tasklistview-bg;
  border-bottom: 1px dashed #BDBDBD; 
  overflow-x: hidden;
  list-style-type: none;
  margin: auto;
}

li {
	padding: 10px 10px 10px 10px;
  margin: 0px 0px 0px 10px; 
  display: list-item;
  background-color: $tasklistview-bg;
}

li.list-group-item.node-task-tree {
  font-size: 16px important;
  text-decoration: none;
  font-family: "SourceSansPro", Helvetica, Arial, sans-serif;
  margin-right 15px;
	list-style: none;
	color: $accessible-placeholder-gray;
  padding: 10px 15px;
}

li.list-group-item.node-task-tree.node-selected {
  background-color: $tasklistview-selected-bg;
  color: darken($accessible-placeholder-gray, 20%);
  border-right: 5px solid $tasklistview-selected-border-right-bg;
  font-weight: 600;
}

li.list-group-item.node-task-tree.selected{
  background-color: $tasklistview-selected-bg;
}


.selected{
	border-right: 5px solid $tasklistview-selected-border-right-bg;
	background-color: $tasklistview-selected-bg;
	font-weight: 600; 
}


//------------------------------------------------------------------------------------------------------------------------
// STATES
//------------------------------------------------------------------------------------------------------------------------

//State = Waiting
span.label.label-Waiting,
span.label.label-pill.label-Waiting {
  	background-color: $state-waiting-bg;
		color: $state-waiting-text;
}

//State = Unassigned
span.label.label-Unassigned,
span.label.label-pill.label-Unassigned {
  	background-color: $state-unassigned-bg;
  	color: $state-unassigned-text; 
}

//State = Assigned
span.label.label-Assigned,
span.label.label-pill.label-Assigned {
  	background-color: $state-assigned-bg;
		color: $state-assigned-text;
}

//State = Accepted
span.label.label-Accepted,
span.label.label-pill.label-Accepted {
  	background-color: $state-accepted-bg;
		color: $state-accepted-text;
}

//State = Rejected
span.label.label-Rejected,
span.label.label-pill.label-Rejected {
 		background-color: $state-rejected-bg;
		color: $state-rejected-text;
}

//State = Work in Scheduled
span.label.label-Work.Scheduled,
span.label.label-pill.label-Work.Scheduled {
  	background-color: $state-workscheduled-bg;
		color: $state-workscheduled-text;
}

//State = Work in Progress
span.label.label-Work.in.Progress,
span.label.label-pill.label-Work.in.Progress {
  	background-color: $state-workinprogress-bg;
		color: $state-workinprogress-text;
}

//State = In Review
span.label.label-In.Review,
span.label.label-pill.label-In.Review {
  	background-color: $state-inreview-bg; 
		color: $state-inreview-text;
}

//State = Rework
span.label.label-Rework,
span.label.label-pill.label-Rework {
  	background-color: $state-rework-bg;
		color: $state-rework-text;
}

//State = Close Complete
span.label.label-Completed,
span.label.label-pill.label-Completed {
  	background-color: $state-completed-bg;
		color: $state-completed-text;
}

//State = Close Incomplete
span.label.label-Closed.Incomplete,
span.label.label-pill.label-Closed.Incomplete {
  	background-color: $state-closedincomplete-bg;
		color: $state-closedincomplete-text;
}

//State = Close Skipped
span.label.label-Cancelled ,
span.label.label-pill.label-Cancelled {
  	background-color: $state-cancelled-bg;
		color: $state-cancelled-text;
}

