 *  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
// RECURSIVE TASK LIST TREE
//------------------------------------------------------------------------------------------------------------------------
// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
//												some special characters in "instruction" or "Signature Instructions" field
//											 Updated some comments in Server Script
//                                          Changes in Client controller
// 2.7.0 | 2021-10-04 | raj  | STRY0105791 - Simple Task Forms- Placeholder Story
//												Changes in Client Script
// 2.7.0 | 2021-10-8 | mmcc | STRY0109110 - Draft Scheduled Tasks – UI – Delete Modal- Add Descendant tasks count
//											In Client controller, updated use of indexof to be findIndex in recordWatch on delete
//                                          Changes in Client controller
// 2.7.0 | 2021-10-8 | raj | DFCT0010588 - When creating a "Subtask" on the "Task" form, record watcher shows 2 subtasks created
//                                          Changes in Client controller
//
// 2.7.0 | 2021-11-16 | raj  | STRY0113839 - Technical Story: Pages/Portal/Page should be picked up from the "Form preferences"
//																					Changes made in Client Script and HTML
//																					NOTE: href was no longer used.  So, removed completely to avoid future confusion
//------------------------------------------------------------------------------------------------------------------------

(function() {
    data.results = [];
    data.table = $sp.getParameter("table");
    data.sys_id = $sp.getParameter("sys_id");

    if ((data.table != 'x_153465_discovert_route_task_instance') || (!data.sys_id)) {
        data.id = null;
        return;
    }

    var gr = new GlideRecordSecure('x_153465_discovert_route_task_instance');
    if (!gr.get(data.sys_id)) {
        return;
    }

    var sys_id_topparenttask = gr.getValue("u_top_task");
    var grTopTask = new GlideRecordSecure('x_153465_discovert_route_task_instance');
    if (!grTopTask.get(sys_id_topparenttask)) {
        return;
    }
    data.task_tree = grTopTask.getValue('u_task_tree');

    var taskWidgetData = new TaskWidgetData();
    data.fieldsInModel = taskWidgetData.loadTaskListTreeFieldsInModelAndFieldLabels(grTopTask);
    taskWidgetData.buildTaskMap('discovertasker-recursivetasktreelist', data.results, grTopTask, data.fieldsInModel);
    data.sc_catalog = $sp.getValue('x_153465_discovert_route_task_instance');

    data.tasks = data.results;
    data.title = gs.getMessage(options.title);
    //data.page = "discovertasker_processdetails"; //before
    data.page = $sp.getParameter("id");

})();
